1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
4	
5	const CURSE_SURCHARGE = 0.5;
6	const HIGH_ENCHANT_SURCHARGE = 0.3;
7	const HIGH_ENCHANT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT = 0.2;
9	const LOYALTY_THRESHOLD = 2;
10	const FIRST_INSURANCE_SURCHARGE = 0.1;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	const DEDUCTIBLE = 100;
13	
14	type Customer = { yearsWithMHPCO: number };
15	type Damage = { itemType: string; amount: number };
16	type Incident = { cause: string; damages: Damage[] };
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
19	type Step = QuoteStep | ClaimStep;
20	type Scenario = { customer: Customer; steps: Step[] };
21	type QuoteResult = { premium: number };
22	type ClaimResult = { payout: number; remainingCap: number };
23	type StepResult = QuoteResult | ClaimResult;
24	
25	const BASE_PREMIUMS: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const INSURANCE_VALUES: Record<string, number> = {
35	  sword: 1000,
36	  amulet: 600,
37	  staff: 800,
38	  potion: 400,
39	  rune: 250,
40	  moonstone: 250,
41	};
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_PREMIUM = 60;
45	const BLOCK_SIZE = 3;
46	
47	const itemSurcharge = (item: Item): number => {
48	  const base = BASE_PREMIUMS[item.type];
49	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
50	  const enchantSurcharge =
51	    (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE : 0;
52	  return curseSurcharge + enchantSurcharge;
53	};
54	
55	const policyBasePremium = (items: Item[]): number => {
56	  const componentCounts: Record<string, number> = {};
57	  let total = 0;
58	  for (const item of items) {
59	    if (COMPONENT_TYPES.has(item.type)) {
60	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
61	    } else {
62	      total += BASE_PREMIUMS[item.type];
63	    }
64	  }
65	  for (const type of Object.keys(componentCounts)) {
66	    const count = componentCounts[type];
67	    if (count === BLOCK_SIZE) {
68	      total += BLOCK_PREMIUM;
69	    } else {
70	      total += count * BASE_PREMIUMS[type];
71	    }
72	  }
73	  return total;
74	};
75	
76	const insuranceSum = (items: Item[]): number =>
77	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
78	
79	const quote = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
80	  const base = policyBasePremium(items);
81	  const surcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
82	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? -base * LOYALTY_DISCOUNT : 0;
83	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
84	  const followUp = isFollowUp ? -base * FOLLOW_UP_DISCOUNT : 0;
85	  const premium = Math.ceil(base + surcharges + loyalty + firstInsurance + followUp + PROCESSING_FEE);
86	  return { premium };
87	};
88	
89	type Policy = {
90	  items: Item[];
91	  remainingCap: number;
92	};
93	
94	const HIGH_ENCHANT_PAYOUT_THRESHOLD = 8;
95	
96	const damagePayout = (damage: Damage, item: Item): number => {
97	  const reimbursed = (item.enchantment ?? 0) >= HIGH_ENCHANT_PAYOUT_THRESHOLD
98	    ? damage.amount / 2
99	    : damage.amount;
100	  return Math.max(0, reimbursed - DEDUCTIBLE);
101	};
102	
103	const findInsuredItem = (policy: Policy, damage: Damage): Item | undefined =>
104	  policy.items.find((item) => item.type === damage.itemType);
105	
106	const claim = (incident: Incident, policy: Policy): ClaimResult => {
107	  const grossPayout = incident.damages.reduce((sum, damage) => {
108	    const item = findInsuredItem(policy, damage);
109	    return item ? sum + damagePayout(damage, item) : sum;
110	  }, 0);
111	  const payout = Math.min(grossPayout, policy.remainingCap);
112	  policy.remainingCap -= payout;
113	  return { payout, remainingCap: policy.remainingCap };
114	};
115	
116	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
117	  let quoteCount = 0;
118	  const policies: Record<number, Policy> = {};
119	  const results: StepResult[] = scenario.steps.map((step, index) => {
120	    if (step.op === "quote") {
121	      const isFollowUp = quoteCount > 0;
122	      quoteCount += 1;
123	      const sum = insuranceSum(step.items);
124	      policies[index] = { items: step.items, remainingCap: sum * 2 };
125	      return quote(step.items, scenario.customer, isFollowUp);
126	    } else {
127	      return claim(step.incident, policies[step.policy]);
128	    }
129	  });
130	  return { results };
131	};
